const input = $input.first().json || {};

function parseIfJsonString(value) {
  if (typeof value !== 'string') return value;
  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
}

function asObject(value) {
  const parsed = parseIfJsonString(value);
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
  return null;
}

function decodeHtml(value) {
  if (typeof value !== 'string') return value;
  return value
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, String.fromCharCode(34))
    .replace(/&#39;/g, String.fromCharCode(39))
    .replace(/&#x27;/g, String.fromCharCode(39))
    .replace(/&#x2F;/g, '/')
    .replace(/&nbsp;/g, ' ');
}

function decodeDeep(data) {
  if (Array.isArray(data)) return data.map(decodeDeep);
  if (data && typeof data === 'object') {
    const out = {};
    for (const key of Object.keys(data)) out[key] = decodeDeep(data[key]);
    return out;
  }
  return decodeHtml(data);
}

function text(value) {
  if (value === null || value === undefined) return null;
  const out = String(value).trim();
  return out === '' ? null : out;
}

function parseDecimal(value) {
  if (value === null || value === undefined || value === '') return null;
  const raw = String(value).trim();
  let normalized = raw;

  if (raw.includes(',') && raw.includes('.')) {
    normalized = raw.replace(/\./g, '').replace(',', '.');
  } else if (raw.includes(',')) {
    normalized = raw.replace(',', '.');
  }

  normalized = normalized.replace(/[^0-9.-]/g, '');
  const n = Number(normalized);
  if (!Number.isFinite(n)) return null;
  return Number(n.toFixed(3));
}

function parseInteger(value) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(String(value).replace(/[^0-9-]/g, ''));
  return Number.isInteger(n) ? n : null;
}

function parseTimestamp(value) {
  if (value === null || value === undefined || value === '') return null;
  const raw = String(value).trim();

  if (/^\d{13}$/.test(raw)) {
    const ms = Number(raw);
    return Number.isFinite(ms) ? Math.floor(ms / 1000) : null;
  }

  if (/^\d{10}$/.test(raw)) {
    const sec = Number(raw);
    return Number.isFinite(sec) ? sec : null;
  }

  const dt = new Date(raw);
  if (Number.isNaN(dt.getTime())) return null;
  return Math.floor(dt.getTime() / 1000);
}

const candidates = [
  asObject(input.body),
  asObject(input),
  asObject(input.original_request?.body),
  asObject(input.original_request),
  asObject(input.query),
  asObject(input.parameters)
].filter(Boolean);

let payload = null;
for (const candidate of candidates) {
  if (Array.isArray(candidate.data?.source?.itens)) {
    payload = candidate;
    break;
  }
}

if (!payload) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Estrutura obrigatoria ausente: data.source.itens' }
  };
}

const itens = decodeDeep(payload.data.source.itens || []);
if (!Array.isArray(itens) || itens.length === 0) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Nenhum item de nota foi recebido' }
  };
}

const notesSeen = new Set();
const records = [];
const errors = [];

for (let i = 0; i < itens.length; i++) {
  const item = itens[i] || {};
  const nota = text(item.Nota);

  if (!nota) {
    errors.push({ index: i, error: 'Nota ausente' });
    continue;
  }

  if (notesSeen.has(nota)) continue;
  notesSeen.add(nota);

  records.push({
    id_registro: text(item.ID),
    nota: nota,
    cliente: text(item.Cliente),
    cnpj: text(item.CNPJ),
    razao_social: text(item.RazaoSocial),
    endereco: text(item.Endereco),
    numero: text(item.Numero),
    complemento: text(item.Complemento),
    bairro: text(item.Bairro),
    cidade: text(item.Cidade),
    estado: text(item.Estado),
    cep: text(item.CEP),
    email: text(item.Email),
    telefone: text(item.Telefone),
    vendedor: text(item.Vendedor),
    valor_produtos: parseDecimal(item.ValorProdutos),
    valor_desconto: parseDecimal(item.ValorDesconto),
    valor_frete: parseDecimal(item.ValorFrete),
    valor_total: parseDecimal(item.ValorTotal),
    total_parcelas: parseInteger(item.TotalParcelas),
    valor_icms: parseDecimal(item.ValorICMS),
    valor_ipi: parseDecimal(item.ValorIPI),
    valor_st: parseDecimal(item.ValorST),
    peso_bruto: parseDecimal(item.PesoBruto),
    peso_liquido: parseDecimal(item.PesoLiquido),
    transportadora: text(item.Transportadora),
    data_pedido: parseTimestamp(item.DataPedido),
    qtde_produtos: parseInteger(item.QtdeProdutos),
    total_unidades: parseInteger(item.TotalUnidades),
    cfop: text(item.CFOP),
    natureza: text(item.Natureza),
    contas: text(item.Contas),
    estoque: text(item.Estoque),
    comissao: text(item.Comissao),
    chave: text(item.Chave),
    protocolo: text(item.Protocolo),
    data_emissao: parseTimestamp(item.DataEmissao),
    data_autorizacao: parseTimestamp(item.DataAutorizacao),
    situacao: text(item.Situacao),
    data_cad: parseTimestamp(item.DataCad),
    data_mod: parseTimestamp(item.DataMod),
    observacoes: text(item.Observacoes),
    observacoes_internas: text(item.ObservacoesInternas),
    categoria_financeira: text(item.CategoriaFinanceira),
    volumes: text(item.Volumes),
    emitido_por: text(item.EmitidoPor),
    cancelado_por: text(item.CanceladoPor),
    data_cancelamento: parseTimestamp(item.DataCancelamento),
    _itens_received: itens.length
  });
}

if (errors.length > 0) {
  return {
    _valid: false,
    statusCode: 400,
    body: {
      ok: false,
      error: 'Um ou mais itens estao invalidos',
      details: errors
    }
  };
}

if (records.length === 0) {
  return {
    _valid: false,
    statusCode: 400,
    body: { ok: false, error: 'Nenhuma nota valida para processar' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'payload_prepared',
  itens_received: itens.length,
  itens_processed: records.length,
  level: 'info'
}));

return {
  _valid: true,
  itens_received: itens.length,
  itens_processed: records.length,
  records
};

const ctx = $items('Validar e Organizar Dados', 0, 0)[0].json;
const rows = Array.isArray(ctx.records) ? ctx.records : [];

const textFields = [
  'id_registro', 'nota', 'cliente', 'cnpj', 'razao_social', 'endereco',
  'numero', 'complemento', 'bairro', 'cidade', 'estado', 'cep', 'email',
  'telefone', 'vendedor', 'transportadora', 'cfop', 'natureza', 'contas',
  'estoque', 'comissao', 'chave', 'protocolo', 'situacao', 'observacoes',
  'observacoes_internas', 'categoria_financeira', 'volumes', 'emitido_por',
  'cancelado_por'
];

const numberFields = [
  'valor_produtos', 'valor_desconto', 'valor_frete', 'valor_total',
  'valor_icms', 'valor_ipi', 'valor_st', 'peso_bruto', 'peso_liquido',
  'total_parcelas', 'qtde_produtos', 'total_unidades'
];

const timestampFields = [
  'data_pedido', 'data_emissao', 'data_autorizacao',
  'data_cad', 'data_mod', 'data_cancelamento'
];

function sql(val) {
  if (val === null || val === undefined || val === '') return 'NULL';
  return "'" + String(val).replace(/\$/g, "$$$$").replace(/'/g, "''") + "'";
}

function sqlTimestamp(epochSeconds) {
  if (epochSeconds === null || epochSeconds === undefined || epochSeconds === '') return 'NULL';
  const n = Number(epochSeconds);
  if (!Number.isFinite(n)) return 'NULL';
  return `to_timestamp(${Math.trunc(n)})`;
}

return rows.map((row) => {
  const out = { ...row };

  for (const field of textFields) {
    out['_' + field] = sql(row[field]);
  }

  for (const field of numberFields) {
    out['_' + field] = row[field] !== undefined && row[field] !== null && row[field] !== ''
      ? Number(row[field])
      : 'NULL';
  }

  for (const field of timestampFields) {
    out['_' + field] = sqlTimestamp(row[field]);
  }

  out._itens_received = ctx.itens_received || rows.length;
  out._itens_processed = ctx.itens_processed || rows.length;

  return out;
});

const prepared = $items('Validar e Organizar Dados', 0, 0)[0].json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'workflow_completed',
  itens_received: prepared.itens_received || 0,
  itens_processed: prepared.itens_processed || 0,
  level: 'info'
}));

return {
  statusCode: 201,
  body: {
    message: 'Fluxo concluido com sucesso',
    itens_received: prepared.itens_received || 0,
    itens_processed: prepared.itens_processed || 0
  }
};

const errData = $items('Salvar Notas de Venda', 1, 0)[0]?.json || $input.first().json || {};

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'db_error',
  message: errData.message || 'Erro ao salvar',
  level: 'error'
}));

return {
  statusCode: 500,
  body: {
    ok: false,
    error: 'Nao foi possivel salvar as notas',
    message: errData.message || 'Falha ao processar o relatorio de notas de venda'
  }
};
